'  --red-dim:rgba(220,60,60,.06);--red-border:rgba(220,80,80,.18);--red:#e05858;',
'  --muted:#7a9ab8;--white:#ffffff;--text:rgba(255,255,255,.85);',
'}',
'*,*::before,*::after{box-sizing:border-box;margin:0;padding:0;}',
'html{scroll-behavior:smooth;}',
'body{background:var(--navy);color:var(--text);font-family:"DM Sans",sans-serif;font-weight:300;overflow-x:hidden;}',
'.pr-progress{position:fixed;top:0;left:0;height:3px;width:0;background:linear-gradient(to right,var(--gold),var(--gold-light));z-index:9999;transition:width .08s linear;pointer-events:none;}',
'.hero{min-height:100vh;display:flex;flex-direction:column;justify-content:center;align-items:center;text-align:center;position:relative;padding:4rem 2rem;overflow:hidden;}',
'.hero-bg{position:absolute;inset:0;background-size:cover;background-position:center 30%;filter:brightness(0.3);transform:scale(1.05);transition:transform 8s ease;}',
'.hero-bg.no-img{background:radial-gradient(circle at 70% 40%,rgba(201,168,76,.18) 0%,transparent 55%),linear-gradient(135deg,#06101e 0%,#0d1e35 100%);filter:none;}',
'.hero:hover .hero-bg{transform:scale(1);}',
'.hero-overlay{position:absolute;inset:0;background:linear-gradient(to bottom,rgba(6,16,30,.2) 0%,rgba(10,22,40,.65) 55%,var(--navy) 100%);}',
'.hero-grid{position:absolute;inset:0;background:repeating-linear-gradient(0deg,transparent,transparent 80px,rgba(201,168,76,.02) 80px,rgba(201,168,76,.02) 81px),repeating-linear-gradient(90deg,transparent,transparent 80px,rgba(201,168,76,.02) 80px,rgba(201,168,76,.02) 81px);}',
'.hero-content{position:relative;z-index:2;max-width:860px;}',
