'.hero h1{font-family:"Playfair Display",serif;font-size:clamp(3rem,8vw,7rem);font-weight:700;line-height:1;letter-spacing:-.02em;animation:fadeUp .8s .15s ease both;color:#fff;}',
'.hero h1 em{font-style:italic;color:var(--gold);font-weight:400;}',
