'.whatsapp-btn{display:inline-flex;align-items:center;gap:.9rem;background:#25D366;color:#fff;padding:1rem 2.4rem;border-radius:100px;font-size:1rem;font-weight:500;letter-spacing:.03em;text-decoration:none;transition:transform .25s,box-shadow .25s;}',
